import json

def generate_and_validate_json(model_call, prompt, max_retries=3):
    current_prompt = prompt
    for i in range(max_retries):
        response = model_call(current_prompt)
        try:
            data = json.loads(response)
            return data
        except json.JSONDecodeError as e:
            current_prompt = f"{prompt}\n\nYour previous output failed validation: {response}\nError details: {str(e)}\nPlease correct the JSON format."
    raise ValueError("Failed to generate valid JSON within retry limits.")
